// até o teto definido pela força usada. Quando a polícia opera/conquista a cidade,
// a investigação é "gasta" como bônus e zerada.
const INVESTIGATION={// Bônus de força aplicado à operação policial (multiplicador): 1 + bonus
// ex.: nível 60 → +60% de força na operação.
bonusMult:lvl=>1+lvl/100,// ganho semanal de nível enquanto investigação está ativa
weeklyGain:force=>Math.max(4,Math.round((force.inv||0)/4)+Math.round((force.power||0)/12)),// teto de nível conforme a força usada (Inteligência Federal vai mais fundo)
cap:force=>Math.min(100,30+(force.inv||0)*0.7+(force.power||0)*0.25)};// ============ SISTEMA DE BASES MILITARES (v38) ============
