const STABILITY_BANDS=[{max:20,label:"COLAPSO",cor:"#7A2030"},{max:40,label:"CRÍTICO",cor:"#C94B4B"},{max:60,label:"INSTÁVEL",cor:"#D98A3F"},{max:80,label:"CONTROLADO",cor:"#D9B25F"},{max:101,label:"ESTÁVEL",cor:"#3FA66A"}];const stabilityBand=v=>STABILITY_BANDS.find(b=>v<=b.max)||STABILITY_BANDS[STABILITY_BANDS.length-1];// status de cada cidade no modo segurança pública
const CITY_STATUS={DOMINADA:{label:"DOMINADA",cor:"#7A2030",icon:"☠"},CONTESTADA:{label:"CONTESTADA",cor:"#C94B4B",icon:"⚔"},SOB_PRESSAO:{label:"SOB PRESSÃO",cor:"#D98A3F",icon:"⚠"},EM_RECUPERACAO:{label:"EM RECUPERAÇÃO",cor:"#5BA0C0",icon:"♻"},ESTABILIZADA:{label:"ESTABILIZADA",cor:"#3FA66A",icon:"✓"},CIDADE_MODELO:{label:"CIDADE MODELO",cor:"#D9B25F",icon:"★"}};const clamp100=v=>Math.max(0,Math.min(100,v));// estabilidade local: presença policial, apoio, economia e infra contra crime e corrupção
function cityStability(c){const s=c.presencaPolicial*0.40+c.apoioPopular*0.30+c.economia*0.20+c.infraestrutura*0.10-c.influenciaCriminosa*0.40-c.corrupcaoLocal*0.20;return clamp100(Math.round(s));}// classifica a cidade conforme influência criminosa / estabilidade
function cityStatus(c){if(c.estabilidade>=90)return"CIDADE_MODELO";if(c.influenciaCriminosa>=80)return"DOMINADA";if(c.influenciaCriminosa>=60)return"CONTESTADA";if(c.estabilidade>=70)return"ESTABILIZADA";if(c.presencaPolicial>c.influenciaCriminosa)return"EM_RECUPERACAO";if(c.influenciaCriminosa>=40)return"SOB_PRESSAO";return"EM_RECUPERACAO";}// estado de segurança pública inicial (objeto securityState)
function initSecurityState(){return{estabilidadeEstadual:50,crimeOrganizado:50,apoioPopular:50,prestigioInstitucional:50,favorabilidadeMidia:50,corrupcaoPolitica:30,nivelAmeaca:"AMARELO",semanasEstaveis:0};}// dados de segurança pública de cada cidade, derivados da classe econômica e dono atual
