function zoneManager(faction,zi){const roster=FACTION_MANAGERS[faction];if(!roster)return null;return roster[((zi*7+3)%4+4)%4];}const TACTIC_LABEL={frontal:"⚡ Ataque Frontal",emboscada:"🌙 Emboscada"};// Monta a ficha de inteligência da zona: efetivo, força, movimentação semanal,
