function intelCapacity(s){let cap=s.intel||0;for(const f of POLICE_FORCES)cap+=(s.forces&&s.forces[f.id]||0)*f.inv;return cap;}// calcula chance de sucesso de uma operação nacional (multifatorial, como pede o documento)
