function claimMission(s,missionId){const list=STRAT_MISSIONS[s.mode]||[];const m=list.find(x=>x.id===missionId);if(!m)return false;if(!(s.missionsReady||[]).includes(missionId))return false;if((s.missionsDone||[]).includes(missionId))return false;const k=s.mode==="pl"?"budget":"cash";s[k]=(s[k]||0)+m.reward;if(m.rep&&s.mode==="pl")s.rep=Math.min(100,s.rep+m.rep);s.missionsReady=(s.missionsReady||[]).filter(x=>x!==missionId);s.missionsDone=[...(s.missionsDone||[]),missionId];chronPush(s,4,s.turn,`Missão cumprida: ${m.name}`,"miss");s._achv=s._achv||[];if(s.missionsDone.length>=5)s._achv.push("missionario");if(s.missionsDone.length>=list.length)s._achv.push("lenda_missoes");return true;}// retorna as próximas missões ativas (não cumpridas), até 3, respeitando progressão de tier
