const DEAL_TYPES={fc:[{id:"paz",name:"Comprar Paz",icon:"🕊",target:"rival",base:80,desc:"Pague para um rival parar de te atacar por algumas semanas.",effect:(s,tgt,ok)=>{if(ok){s.truce=s.truce||{};s.truce[tgt]=s.turn+4;}}},{id:"divisao",name:"Dividir Território",icon:"🗺",target:"rival",base:120,desc:"Proponha um acordo de zonas — menos guerra, mais lucro.",effect:(s,tgt,ok)=>{if(ok){s.truce=s.truce||{};s.truce[tgt]=s.turn+6;s.morale=Math.min(100,s.morale+5);}}},{id:"alianca",name:"Propor Aliança",icon:"🤝",target:"rival",base:200,desc:"Una forças contra um inimigo comum. Arriscado, mas poderoso.",effect:(s,tgt,ok)=>{if(ok){s.alliances=s.alliances||{};s.alliances[tgt]=true;s.truce=s.truce||{};s.truce[tgt]=s.turn+10;}}}],pl:[{id:"informe",name:"Comprar Informação",icon:"📋",target:"rival",base:60,desc:"Suborne um membro do rival por inteligência sobre suas zonas.",effect:(s,tgt,ok)=>{if(ok){s.intel=(s.intel||0)+3;s.rep=Math.min(100,s.rep+3);}}},{id:"render",name:"Negociar Rendição",icon:"🏳",target:"rival",base:150,desc:"Ofereça acordo de delação para um rival entregar uma zona.",effect:(s,tgt,ok)=>{if(ok){const z=s.terr.findIndex(t=>t.owner===tgt);if(z>=0){s.terr[z].owner="pl";s.terr[z].str=0;}}}},{id:"verba_extra",name:"Barganhar Verba",icon:"🏛",target:"gov",base:100,desc:"Negocie com o governo uma injeção extra de verba de pacificação.",effect:(s,tgt,ok)=>{if(ok){s.budget+=150;s.govAlliance=Math.min(6,(s.govAlliance||0)+1);}}}]};// avalia uma oferta: retorna { accept, counter, betray }
function evalDeal(s,deal,offer,targetId){const isPol=s.mode==="pl";const fair=deal.base;// oferta "justa"
const ratio=offer/fair;// quão generosa é a oferta
// relação com o alvo (rivais hostis pedem mais; medo ajuda)
let hostility=0.5;if(deal.target==="rival"&&RIVAL_AI[targetId]){hostility=RIVAL_AI[targetId].aggro||0.6;if(s.vendetta&&s.vendetta[targetId]&&s.vendetta[targetId].grudge>40)hostility+=0.25;}const fearBonus=s.status&&s.status.med?Math.min(0.2,s.status.med*0.008):0;// chance de aceitar cresce com a generosidade e o medo, cai com a hostilidade
const acceptChance=clamp(ratio*0.6+fearBonus-hostility*0.3,0.05,0.95);const r=Math.random();if(r<acceptChance){// aceitou — mas rivais hostis podem trair
const betrayChance=deal.target==="rival"?clamp(hostility*0.25-fearBonus,0,0.3):0;return{accept:true,betray:Math.random()<betrayChance};}// não aceitou direto — se a oferta foi razoável, faz contraproposta
if(ratio>=0.6&&ratio<1.3)return{accept:false,counter:Math.round(fair*(1.3+hostility*0.4))};return{accept:false,counter:null};}// ============ MOEDA EM ESCALA REAL (v22) ============
// Âncora: 1 unidade interna do jogo = 1 salário mínimo do Brasil (2026 = R$ 1.621).
