const MUSIC_SRC="assets/audio/trilha.mp3";const MUSIC_VOL=0.45;let musicEl=null;const ensureMusicEl=()=>{if(musicEl||typeof window==="undefined"||!window.Audio)return musicEl;try{musicEl=new window.Audio(MUSIC_SRC);musicEl.loop=true;musicEl.preload="auto";musicEl.volume=MUSIC_VOL;}catch(e){musicEl=null;}return musicEl;};// Inicia a trilha. Só toca se música estiver ligada; navegadores exigem um gesto
